355	static void BoundaryPMFinal(Node *(*lists)[2],
356	                            Node *leaves, int numsymbols, NodePool *pool, int index)
357	{
358	    int lastcount = lists[index][1]->count; /* Count of last chain of list. */
359	
360	    size_t sum = lists[index - 1][0]->weight + lists[index - 1][1]->weight;
361	
362	    if (lastcount < numsymbols && sum > leaves[lastcount].weight)
363	    {
364	        Node *newchain = pool->next;
365	        Node *oldchain = lists[index][1]->tail;
366	
367	        lists[index][1] = newchain;
368	        newchain->count = lastcount + 1;
369	        newchain->tail = oldchain;
370	    }
371	    else
372	    {
373	        lists[index][1]->tail = lists[index - 1][1];
374	    }
