377	/*
378	Performs a Boundary Package-Merge step. Puts a new chain in the given list. The
379	new chain is, depending on the weights, a leaf or a combination of two chains
380	from the previous list.
381	lists: The lists of chains.
382	maxbits: Number of lists.
383	leaves: The leaves, one per symbol.
384	numsymbols: Number of leaves.
385	pool: the node memory pool.
386	index: The index of the list in which a new chain or leaf is required.
387	*/
388	/* Maximum number of chain lists. In DEFLATE the bit lengths are limited to 15,
389	   so the boundary package-merge never uses more lists than this. It bounds the
390	   structural unrolling of the precondition below. */
391	#define BOUNDARYPM_MAXLISTS 15
392	
393	/* For chain list k (when it is within the active range k <= index): both chain
394	   pointers point to fresh Nodes, and the "last chain" carries a leaf count in
395	   [0, numsymbols]. The count bound keeps leaves[lastcount] accesses in range. */
396	#define BOUNDARYPM_LIST_VALID(k)                          \
397	    ((k) > index ||                                       \
398	     (__CPROVER_is_fresh(lists[k][0], sizeof(Node)) &&    \
399	      __CPROVER_is_fresh(lists[k][1], sizeof(Node)) &&    \
400	      0 <= lists[k][1]->count && lists[k][1]->count <= numsymbols))
401	
402	static void BoundaryPM(Node *(*lists)[2], Node *leaves, int numsymbols,
403	                       NodePool *pool, int index)
404	__CPROVER_requires(index >= 0 && index < BOUNDARYPM_MAXLISTS)
405	__CPROVER_requires(numsymbols >= 1 && numsymbols < INT_MAX)
406	__CPROVER_requires(
407	    __CPROVER_is_fresh(lists, (size_t)BOUNDARYPM_MAXLISTS * sizeof(*lists)))
408	__CPROVER_requires(__CPROVER_is_fresh(leaves, (size_t)numsymbols * sizeof(*leaves)))
409	__CPROVER_requires(__CPROVER_is_fresh(pool, sizeof(*pool)))
410	__CPROVER_requires(__CPROVER_is_fresh(
411	    pool->next, ((size_t)index + 1) * 2 * (size_t)numsymbols * sizeof(Node)))
412	__CPROVER_requires(
413	    BOUNDARYPM_LIST_VALID(0) && BOUNDARYPM_LIST_VALID(1) &&
414	    BOUNDARYPM_LIST_VALID(2) && BOUNDARYPM_LIST_VALID(3) &&
415	    BOUNDARYPM_LIST_VALID(4) && BOUNDARYPM_LIST_VALID(5) &&
416	    BOUNDARYPM_LIST_VALID(6) && BOUNDARYPM_LIST_VALID(7) &&
417	    BOUNDARYPM_LIST_VALID(8) && BOUNDARYPM_LIST_VALID(9) &&
418	    BOUNDARYPM_LIST_VALID(10) && BOUNDARYPM_LIST_VALID(11) &&
419	    BOUNDARYPM_LIST_VALID(12) && BOUNDARYPM_LIST_VALID(13) &&
420	    BOUNDARYPM_LIST_VALID(14))
421	__CPROVER_assigns(pool->next)
422	__CPROVER_assigns(__CPROVER_object_whole(lists))
423	__CPROVER_assigns(__CPROVER_object_whole(pool->next))
424	__CPROVER_ensures(__CPROVER_rw_ok(lists[index][1], sizeof(Node)))
425	__CPROVER_ensures(pool->next >= __CPROVER_old(pool->next))
426	{
427	    Node *newchain;
428	    Node *oldchain;
429	    int lastcount = lists[index][1]->count; /* Count of last chain of list. */
430	
431	    if (index == 0 && lastcount >= numsymbols)
432	        return;
433	
434	    newchain = pool->next++;
435	    oldchain = lists[index][1];
436	
437	    /* These are set up before the recursive calls below, so that there is a list
438	    pointing to the new node, to let the garbage collection know it's in use. */
439	    lists[index][0] = oldchain;
440	    lists[index][1] = newchain;
441	
442	    if (index == 0)
443	    {
444	        /* New leaf node in list 0. */
445	        InitNode(leaves[lastcount].weight, lastcount + 1, 0, newchain);
446	    }
447	    else
448	    {
449	        size_t sum = lists[index - 1][0]->weight + lists[index - 1][1]->weight;
450	        if (lastcount < numsymbols && sum > leaves[lastcount].weight)
451	        {
452	            /* New leaf inserted in list, so count is incremented. */
453	            InitNode(leaves[lastcount].weight, lastcount + 1, oldchain->tail,
454	                     newchain);
455	        }
456	        else
457	        {
458	            InitNode(sum, lastcount, lists[index - 1][1], newchain);
459	            /* Two lookahead chains of previous list used up, create new ones. */
460	            BoundaryPM(lists, leaves, numsymbols, pool, index - 1);
461	            BoundaryPM(lists, leaves, numsymbols, pool, index - 1);
462	        }
463	    }
464	}
