466	/*
467	Outputs minimum-redundancy length-limited code bitlengths for symbols with the
468	given counts. The bitlengths are limited by maxbits.
469	
470	The output is tailored for DEFLATE: symbols that never occur, get a bit length
471	of 0, and if only a single symbol occurs at least once, its bitlength will be 1,
472	and not 0 as would theoretically be needed for a single symbol.
473	
474	frequencies: The amount of occurrences of each symbol.
475	n: The amount of symbols.
476	maxbits: Maximum bit length, inclusive.
477	bitlengths: Output, the bitlengths for the symbol prefix codes.
478	return: 0 for OK, non-0 for error.
479	*/
480	int ZopfliLengthLimitedCodeLengths(
481	    const size_t *frequencies, int n, int maxbits, unsigned *bitlengths)
482	{
483	    NodePool pool;
484	    int i;
485	    int numsymbols = 0; /* Amount of symbols with frequency > 0. */
486	    int numBoundaryPMRuns;
487	    Node *nodes;
488	
489	    /* Array of lists of chains. Each list requires only two lookahead chains at
490	    a time, so each list is a array of two Node*'s. */
491	    Node *(*lists)[2];
492	
493	    /* One leaf per symbol. Only numsymbols leaves will be used. */
494	    Node *leaves = (Node *)malloc(n * sizeof(*leaves));
495	
496	    /* Initialize all bitlengths at 0. */
497	    for (i = 0; i < n; i++)
498	    {
499	        bitlengths[i] = 0;
500	    }
501	
502	    /* Count used symbols and place them in the leaves. */
503	    for (i = 0; i < n; i++)
504	    {
505	        if (frequencies[i])
506	        {
507	            leaves[numsymbols].weight = frequencies[i];
508	            leaves[numsymbols].count = i; /* Index of symbol this leaf represents. */
509	            numsymbols++;
510	        }
511	    }
512	
513	    /* Check special cases and error conditions. */
514	    if ((1 << maxbits) < numsymbols)
515	    {
516	        free(leaves);
517	        return 1; /* Error, too few maxbits to represent symbols. */
518	    }
519	    if (numsymbols == 0)
520	    {
521	        free(leaves);
522	        return 0; /* No symbols at all. OK. */
523	    }
524	    if (numsymbols == 1)
525	    {
526	        bitlengths[leaves[0].count] = 1;
527	        free(leaves);
528	        return 0; /* Only one symbol, give it bitlength 1, not 0. OK. */
529	    }
530	    if (numsymbols == 2)
531	    {
532	        bitlengths[leaves[0].count]++;
533	        bitlengths[leaves[1].count]++;
534	        free(leaves);
535	        return 0;
536	    }
537	
538	    /* Sort the leaves from lightest to heaviest. Add count into the same
539	    variable for stable sorting. */
540	    for (i = 0; i < numsymbols; i++)
541	    {
542	        if (leaves[i].weight >=
543	            ((size_t)1 << (sizeof(leaves[0].weight) * CHAR_BIT - 9)))
544	        {
545	            free(leaves);
546	            return 1; /* Error, we need 9 bits for the count. */
547	        }
548	        leaves[i].weight = (leaves[i].weight << 9) | leaves[i].count;
549	    }
550	    qsort(leaves, numsymbols, sizeof(Node), LeafComparator);
551	    for (i = 0; i < numsymbols; i++)
552	    {
553	        leaves[i].weight >>= 9;
554	    }
555	
556	    if (numsymbols - 1 < maxbits)
557	    {
558	        maxbits = numsymbols - 1;
559	    }
560	
561	    /* Initialize node memory pool. */
562	    nodes = (Node *)malloc(maxbits * 2 * numsymbols * sizeof(Node));
563	    pool.next = nodes;
564	
565	    lists = (Node * (*)[2]) malloc(maxbits * sizeof(*lists));
566	    InitLists(&pool, leaves, maxbits, lists);
567	
568	    /* In the last list, 2 * numsymbols - 2 active chains need to be created. Two
569	    are already created in the initialization. Each BoundaryPM run creates one. */
570	    numBoundaryPMRuns = 2 * numsymbols - 4;
571	    for (i = 0; i < numBoundaryPMRuns - 1; i++)
572	    {
573	        BoundaryPM(lists, leaves, numsymbols, &pool, maxbits - 1);
574	    }
575	    BoundaryPMFinal(lists, leaves, numsymbols, &pool, maxbits - 1);
576	
577	    ExtractBitLengths(lists[maxbits - 1][1], leaves, bitlengths);
578	
579	    free(lists);
580	    free(leaves);
581	    free(nodes);
582	    return 0; /* OK. */
583	}
