597	/*
598	Adds bits, like AddBits, but the order is inverted. The deflate specification
599	uses both orders in one standard.
600	*/
601	static void AddHuffmanBits(unsigned symbol, unsigned length,
602	                           unsigned char *bp, unsigned char **out,
603	                           size_t *outsize)
604	/* bp, out, outsize must be valid pointers. */
605	__CPROVER_requires(__CPROVER_is_fresh(bp, sizeof(*bp)))
606	__CPROVER_requires(__CPROVER_is_fresh(outsize, sizeof(*outsize)))
607	__CPROVER_requires(__CPROVER_is_fresh(out, sizeof(*out)))
608	/* *bp is a bit index within a byte, used as a shift amount. */
609	__CPROVER_requires(*bp <= 7)
610	/* Every caller emits a single Huffman code whose length is at most 7 bits here,
611	   so the bit cursor wraps to 0 at most once and thus at most a single fresh byte
612	   is appended over the whole loop. */
613	__CPROVER_requires(length <= 7)
614	/* The buffer holds at least one byte that can be updated, plus room to append
615	   one more byte without overflowing.  Constraining *outsize to a non-power-of-
616	   two (and non-zero) value keeps the ZOPFLI_APPEND_DATA macro on its
617	   no-reallocation path for that single append. */
618	__CPROVER_requires(((*outsize) & ((*outsize) - 1)) != 0)
619	__CPROVER_requires(__CPROVER_is_fresh(*out, (*outsize) + 1))
620	__CPROVER_assigns(*bp, *outsize, __CPROVER_object_whole(*out))
621	/* One fresh byte is appended for each time the bit cursor lands on 0 while
622	   emitting the `length` bits. */
623	__CPROVER_ensures(*outsize ==
624	                  __CPROVER_old(*outsize)
625	                      + ((__CPROVER_old(*bp) + length + 7) / 8
626	                         - (__CPROVER_old(*bp) + 7) / 8))
627	/* The bit cursor advances by `length`, modulo 8. */
628	__CPROVER_ensures(*bp == ((__CPROVER_old(*bp) + length) & 7))
629	{
630	    /* TODO(lode): make more efficient (add more bits at once). */
631	    unsigned i;
632	    for (i = 0; i < length; i++)
633	    {
634	        unsigned bit = (symbol >> (length - i - 1)) & 1;
635	        if (*bp == 0)
636	            ZOPFLI_APPEND_DATA(0, out, outsize);
637	        (*out)[*outsize - 1] |= bit << *bp;
638	        *bp = (*bp + 1) & 7;
639	    }
640	}
