683	Converts a series of Huffman tree bitlengths, to the bit values of the symbols.
684	*/
685	void ZopfliLengthsToSymbols(const unsigned *lengths, size_t n, unsigned maxbits,
686	                            unsigned *symbols)
687	{
688	    size_t *bl_count = (size_t *)malloc(sizeof(size_t) * (maxbits + 1));
689	    size_t *next_code = (size_t *)malloc(sizeof(size_t) * (maxbits + 1));
690	    unsigned bits, i;
691	    unsigned code;
692	
693	    for (i = 0; i < n; i++)
694	    {
695	        symbols[i] = 0;
696	    }
697	
698	    /* 1) Count the number of codes for each code length. Let bl_count[N] be the
699	    number of codes of length N, N >= 1. */
700	    for (bits = 0; bits <= maxbits; bits++)
701	    {
702	        bl_count[bits] = 0;
703	    }
704	    for (i = 0; i < n; i++)
705	    {
706	        assert(lengths[i] <= maxbits);
707	        bl_count[lengths[i]]++;
708	    }
709	    /* 2) Find the numerical value of the smallest code for each code length. */
710	    code = 0;
711	    bl_count[0] = 0;
712	    for (bits = 1; bits <= maxbits; bits++)
713	    {
714	        code = (code + bl_count[bits - 1]) << 1;
715	        next_code[bits] = code;
716	    }
717	    /* 3) Assign numerical values to all codes, using consecutive values for all
718	    codes of the same length with the base values determined at step 2. */
719	    for (i = 0; i < n; i++)
720	    {
721	        unsigned len = lengths[i];
722	        if (len != 0)
723	        {
724	            symbols[i] = next_code[len];
725	            next_code[len]++;
726	        }
727	    }
728	
729	    free(bl_count);
730	    free(next_code);
731	}
