symbol.
*/
void ZopfliCalculateBitLengths(const size_t *count, size_t n, int maxbits,
                               unsigned *bitlengths)
{
    int error = ZopfliLengthLimitedCodeLengths(count, n, maxbits, bitlengths);
    (void)error;
    assert(!error);
}

